What is the output of the following code?

console.log(1 + '2' + 3);
console.log(1 + 2 + '3');

What will be logged to the console?

for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 0);
}

What will be logged to the console?

for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 0);
}

What is the output?

console.log([] + []);
console.log([] + {});
console.log({} + []);

What is the output of the following code?

function outer() {
  let count = 0;
  return function() {
    count++;
    return count;
  };
}
const counter = outer();
console.log(counter());
console.log(counter());
console.log(counter());

What is the output of the following code?

async function foo() {
  console.log('A');
  await Promise.resolve();
  console.log('B');
}
console.log('C');
foo();
console.log('D');

What is the output?

const arr = [1, 2, 3];
const result = arr.filter(n => n > 1).map(n => n * 2);
console.log(result);

What is the output?

const obj = { a: 1, b: 2 };
const { a, ...rest } = obj;
console.log(a, rest);

What will happen when this component renders?

function Counter() {
  const [count, setCount] = useState(0);
  console.log('Render');
  return <button onClick={() => setCount(count + 1)}>{count}</button>;
}

What is wrong with this code?

function Timer() {
  const [seconds, setSeconds] = useState(0);
  useEffect(() => {
    setInterval(() => setSeconds(seconds + 1), 1000);
  }, []);
  return <div>{seconds}</div>;
}

What is the output order?

console.log('1');
setTimeout(() => console.log('2'), 0);
Promise.resolve().then(() => console.log('3'));
console.log('4');

What is the output?

function delay() {
  return new Promise(resolve => setTimeout(() => resolve('done'), 100));
}
async function run() {
  const result = await delay();
  console.log(result);
}
run();
console.log('started');
